import{_ as o,o as a,c as e,a3 as r}from"./chunks/framework.BTFg6ESq.js";const g=JSON.parse('{"title":"符号链接搬家工具","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/symlink-mover.md","filePath":"user-guide/tools/symlink-mover.md","lastUpdated":1778221347000}'),i={name:"user-guide/tools/symlink-mover.md"};function l(d,t,n,s,h,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="符号链接搬家工具" tabindex="-1">符号链接搬家工具 <a class="header-anchor" href="#符号链接搬家工具" aria-label="Permalink to &quot;符号链接搬家工具&quot;">​</a></h1><blockquote><p><strong>给文件「挪窝」的同时，在原位置留个「传送门」，让所有依赖路径保持有效。</strong></p></blockquote><h2 id="功能概览" tabindex="-1">功能概览 <a class="header-anchor" href="#功能概览" aria-label="Permalink to &quot;功能概览&quot;">​</a></h2><ul><li><strong>搬家模式</strong> — 将文件/文件夹移动到新位置，原位置自动创建符号链接或硬链接，所有引用该路径的程序不受影响</li><li><strong>仅创建链接模式</strong> — 不移动原文件，直接在目标目录生成链接，适合为散落文件建立统一访问入口</li><li><strong>支持符号链接与硬链接</strong> — 符号链接可跨分区、可链接目录；硬链接与源文件平权，删除任一方不影响另一方</li><li><strong>镜像搬家模式</strong> — 保持源目录的完整层级结构，适合整体迁移项目文件夹</li><li><strong>操作日志与进度追踪</strong> — 实时查看复制进度，每次操作自动记录结果，方便追溯</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="场景一-为占用空间的文件夹「腾地方」" tabindex="-1">场景一：为占用空间的文件夹「腾地方」 <a class="header-anchor" href="#场景一-为占用空间的文件夹「腾地方」" aria-label="Permalink to &quot;场景一：为占用空间的文件夹「腾地方」&quot;">​</a></h3><p><strong>问题</strong>：<code>D:/Downloads/Games/</code> 下的游戏资源占满了系统盘，你想把它们移到 <code>E:/Archive/Games/</code>，但 Steam 等启动器坚持要读原来的路径。</p><p><strong>操作步骤</strong>：</p><ol><li>在工具页面中，点击「选择文件夹」按钮，找到 <code>D:/Downloads/Games/</code></li><li>右侧「操作模式」确认选中 <strong>搬家模式</strong></li><li>点击「目标目录」的「选择」按钮，定位到 <code>E:/Archive/Games/</code></li><li>「链接类型」保持默认的 <strong>符号链接</strong></li><li>点击底部 <strong>「开始搬家」</strong> 按钮</li></ol><p>结果：文件全部移到了 <code>E:/Archive/Games/</code>，而 <code>D:/Downloads/Games/</code> 位置留下了一个符号链接，启动器仍然可以正常读取。</p><h3 id="场景二-给散落的配置文件建一个统一入口" tabindex="-1">场景二：给散落的配置文件建一个统一入口 <a class="header-anchor" href="#场景二-给散落的配置文件建一个统一入口" aria-label="Permalink to &quot;场景二：给散落的配置文件建一个统一入口&quot;">​</a></h3><p><strong>问题</strong>：<code>.npmrc</code>、<code>.gitconfig</code>、<code>.ssh/config</code> 散落在用户目录各个角落，你想在 <code>D:/Configs/</code> 集中管理。</p><p><strong>操作步骤</strong>：</p><ol><li>切换操作模式为 <strong>仅创建链接</strong></li><li>逐一添加这些配置文件（支持拖拽或文件选择器）</li><li>目标目录选 <code>D:/Configs/</code></li><li>链接类型保持 <strong>符号链接</strong></li><li>点击 <strong>「创建链接」</strong></li></ol><p>结果：原文件不动，<code>D:/Configs/</code> 下生成了指向它们的符号链接，方便统一浏览和管理。</p><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="操作模式" tabindex="-1">操作模式 <a class="header-anchor" href="#操作模式" aria-label="Permalink to &quot;操作模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>行为</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>搬家模式</strong></td><td>将源文件移动到目标目录，原位置创建链接</td><td>释放磁盘空间，同时保持旧路径可用</td></tr><tr><td><strong>仅创建链接</strong></td><td>源文件不动，仅在目标目录创建链接</td><td>集中管理分散的文件，不作物理移动</td></tr></tbody></table><h3 id="链接类型对比" tabindex="-1">链接类型对比 <a class="header-anchor" href="#链接类型对比" aria-label="Permalink to &quot;链接类型对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>符号链接（Symlink）</th><th>硬链接（Hard Link）</th></tr></thead><tbody><tr><td>跨分区/跨盘</td><td>✅ 支持</td><td>❌ 不支持</td></tr><tr><td>链接目录</td><td>✅ 支持</td><td>❌ 不支持</td></tr><tr><td>源文件删除后</td><td>❌ 链接失效</td><td>✅ 另一个副本仍在</td></tr><tr><td>文件平等性</td><td>链接是「快捷方式」</td><td>与原文件数据完全平等</td></tr><tr><td>⚠️ 链接限制</td><td>—</td><td>仅链接模式下不支持硬链接</td></tr></tbody></table><blockquote><p><strong>如何选择？</strong> 日常使用首选符号链接，它灵活、无限制。硬链接仅在需要「文件多副本但物理只存一份」时适用（如代码仓库的 node_modules）。</p></blockquote><h3 id="镜像搬家模式" tabindex="-1">镜像搬家模式 <a class="header-anchor" href="#镜像搬家模式" aria-label="Permalink to &quot;镜像搬家模式&quot;">​</a></h3><p>当源目录结构需要完整保留时，开启「镜像搬家模式」并指定 <strong>基准源目录</strong>。</p><p><strong>示例</strong>：</p><ul><li>源文件：<code>D:/Projects/MyApp/src/components/Button.vue</code></li><li>基准源目录：<code>D:/Projects/MyApp/</code></li><li>目标目录：<code>E:/Archives/MyApp/</code></li><li>搬家后目标路径：<code>E:/Archives/MyApp/src/components/Button.vue</code></li></ul><p>不加镜像模式时，目标目录会是 <code>E:/Archives/MyApp/Button.vue</code>，层级丢了。</p><h3 id="文件列表管理" tabindex="-1">文件列表管理 <a class="header-anchor" href="#文件列表管理" aria-label="Permalink to &quot;文件列表管理&quot;">​</a></h3><ul><li><strong>添加方式</strong>：支持文件选择器、文件夹选择器、手动输入路径、拖拽文件/文件夹</li><li><strong>自动去重</strong>：相同路径不会重复添加</li><li><strong>状态标识</strong>：待处理（pending）、处理中（processing）、成功（success）、错误（error）</li><li><strong>验证反馈</strong>：添加文件后自动验证，硬链接跨分区或链接目录时会显示警告</li></ul><h3 id="进度与日志" tabindex="-1">进度与日志 <a class="header-anchor" href="#进度与日志" aria-label="Permalink to &quot;进度与日志&quot;">​</a></h3><ul><li><strong>实时进度条</strong>：显示当前正在复制的文件名、已复制字节数、总字节数、百分比进度</li><li><strong>操作日志滚动条</strong>：底部区域显示最近一次操作摘要（模式+链接类型+成功数+耗时+大小）</li><li><strong>日志详情弹窗</strong>：点击日志滚动条可查看完整历史记录，包含每次操作的时间、类型、成功/失败统计、错误详情</li></ul><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="通过-llm-调用" tabindex="-1">通过 LLM 调用 <a class="header-anchor" href="#通过-llm-调用" aria-label="Permalink to &quot;通过 LLM 调用&quot;">​</a></h3><p>该工具已注册为系统服务，LLM 可以根据上下文自动调用。支持以下操作：</p><ul><li><code>moveAndLink()</code> — 执行搬家操作</li><li><code>createLinksOnly()</code> — 仅创建链接</li><li><code>getLatestOperationSummary()</code> — 获取最近一次操作摘要</li><li><code>getOperationHistory(limit?)</code> — 获取操作历史</li></ul><h3 id="批量处理大型文件夹" tabindex="-1">批量处理大型文件夹 <a class="header-anchor" href="#批量处理大型文件夹" aria-label="Permalink to &quot;批量处理大型文件夹&quot;">​</a></h3><p>处理包含数百个文件的大型目录时，工具提供：</p><ul><li><strong>取消操作</strong>：处理过程中可随时取消，已移动的文件不会回滚，未处理的文件保持原状</li><li><strong>逐文件状态追踪</strong>：每个文件独立记录成功/失败状态，支持查看失败详情</li><li><strong>错误隔离</strong>：单个文件失败不会影响其他文件的处理</li></ul><h3 id="配合目录清洁工具" tabindex="-1">配合目录清洁工具 <a class="header-anchor" href="#配合目录清洁工具" aria-label="Permalink to &quot;配合目录清洁工具&quot;">​</a></h3><p>搬家完成后，建议使用[目录清洁工具](./directory-janitor)扫描原目录中的空文件夹和残留文件，彻底清理磁盘空间。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么硬链接选项是灰色的" tabindex="-1">为什么硬链接选项是灰色的？ <a class="header-anchor" href="#为什么硬链接选项是灰色的" aria-label="Permalink to &quot;为什么硬链接选项是灰色的？&quot;">​</a></h3><p><strong>仅创建链接</strong>模式下不支持硬链接，因为硬链接需要源文件和目标在同一分区，且不能链接目录。如果需要在不同分区操作，请使用符号链接。</p><h3 id="搬家到一半能取消吗-已移动的文件会怎样" tabindex="-1">搬家到一半能取消吗？已移动的文件会怎样？ <a class="header-anchor" href="#搬家到一半能取消吗-已移动的文件会怎样" aria-label="Permalink to &quot;搬家到一半能取消吗？已移动的文件会怎样？&quot;">​</a></h3><p>可以随时点击「取消操作」按钮。已移动的文件不会自动回滚。这是一种权衡设计——根据场景选择继续手动清理或保持现状。</p><h3 id="操作日志存在哪里-能持久化多久" tabindex="-1">操作日志存在哪里？能持久化多久？ <a class="header-anchor" href="#操作日志存在哪里-能持久化多久" aria-label="Permalink to &quot;操作日志存在哪里？能持久化多久？&quot;">​</a></h3><p>日志通过 Tauri 后端持久化存储在本地，每次操作都会写入日志文件。可以在日志弹窗中查看所有历史记录，不受重启影响。</p><h3 id="符号链接和-windows-快捷方式有什么区别" tabindex="-1">符号链接和 Windows 快捷方式有什么区别？ <a class="header-anchor" href="#符号链接和-windows-快捷方式有什么区别" aria-label="Permalink to &quot;符号链接和 Windows 快捷方式有什么区别？&quot;">​</a></h3><p>符号链接（Symlink）是文件系统级别的链接，<strong>对应用程序完全透明</strong>。程序访问链接路径时，操作系统会自动重定向到目标路径，程序本身感知不到。而快捷方式（<code>.lnk</code>）是文件级引用，只有 Windows 资源管理器和部分程序识别。</p><h3 id="拖拽文件和文件夹有什么限制" tabindex="-1">拖拽文件和文件夹有什么限制？ <a class="header-anchor" href="#拖拽文件和文件夹有什么限制" aria-label="Permalink to &quot;拖拽文件和文件夹有什么限制？&quot;">​</a></h3><p>支持从文件资源管理器（资源管理器）拖拽文件和文件夹到工具的文件列表区域。拖放区域会高亮提示。也支持将目录拖拽到目标目录和基准源目录的输入框中。</p><h2 id="参见" tabindex="-1">参见 <a class="header-anchor" href="#参见" aria-label="Permalink to &quot;参见&quot;">​</a></h2><ul><li><a href="./directory-janitor">目录清洁工具</a> — 搬家后清理残留空文件夹</li><li><a href="./directory-tree">目录结构浏览器</a> — 查看搬家后的目录结构</li><li><a href="./index">工具总览</a> — 查看所有可用工具</li></ul>',52)])])}const p=o(i,[["render",l]]);export{g as __pageData,p as default};
